var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"으음……","JPN":"ううむ……","ENG":"Mm...","TWN":"唔……"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너무 갑자기 움직이지 마세요, 사나에.","JPN":"いきなり動かないでください、早苗。","ENG":"Do not move so hastily, Sanae.","TWN":"動作不要太大，早苗。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"상처의 출혈이 멎었군요.","JPN":"出血が止まりましたね。","ENG":"My bleeding has stopped.","TWN":"傷口的出血止住了。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"또 사람들을 치료해주고 계신 겁니까?","JPN":"また人々の手当をしていらっしゃるのですか？","ENG":"Were you treating people again?","TWN":"您又替人治療嗎？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께서도 많이 지치셨을 텐데요.","JPN":"ご当主様もそうとうお疲れのはずですが。","ENG":"But you must be exhausted.","TWN":"堂主應該也很疲憊吧？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 괜찮아요. 제가 무사한 건 모두의 도움이 있었기 때문인 걸요.","JPN":"私は平気です。私が無事なのは皆さんの助けがあってこそですから。","ENG":"I am all right. I am safe due to everyone's help.","TWN":"我沒事，我之所以能夠平安無事，也都是因為有大家幫忙。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님은……?","JPN":"千冬様は……？","ENG":"And Miss Chifuyu...?","TWN":"千冬呢……？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"역귀들과 싸우고 있어요.","JPN":"疫鬼たちと戦っています。","ENG":"She is fighting the Plagued Ghosts.","TWN":"正在對付疫鬼。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"피에 잠시나마 저항하는 것 같아 보였지만…… 이미 한계이겠죠.","JPN":"血に少しは抵抗しているように見えましたけど……もう限界でしょう。","ENG":"I thought she was resisting the blood, but... I think she has reached her limit.","TWN":"看起來她暫時能抵抗血液的侵蝕……不過應該已經差不多到達極限。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라 당주.","JPN":"七原当主。","ENG":"Lady Nanahara.","TWN":"七原堂主。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……나오님.","JPN":"……ナオ様。","ENG":"...Miss Nao.","TWN":"……奈緒大人。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송해요. 저는 결국…… 아무것도 바꾸지 못했습니다.","JPN":"すみません。私は結局……何も変えられませんでした。","ENG":"Forgive me. I... could not change anything.","TWN":"對不起，結果……我也什麼都沒能改變。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주가 되어서, 포기라도 할 셈이냐?","JPN":"当主なのに、諦めるつもりか？","ENG":"Are you going to give up that easily?","TWN":"你當堂主的目的是想放棄嗎？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저들은 미래를 알고 있지만…… 저는 아무것도 들을 수 없습니다.","JPN":"彼らは未来を知っていますが……私は何も聞くことができません。","ENG":"They know what the future holds. However... I cannot hear anything.","TWN":"他們知道未來……但我卻什麼都聽不到。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금까지 전부 저들의 계획에 당해왔는데, 이제 와서 뭘 할 수 있나요?","JPN":"今まで全部彼らの計画どおりにやられてきたのに、今さら何ができるのですか？","ENG":"We have been straggled along into their plan. So what is there that I can do?","TWN":"到現在為止，全都被他們的計畫牽著鼻子走，我現在還能做什麼？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래, 우리가 놓친 기회들을 만회하기엔 너무 늦었지.","JPN":"わしらが逃した機会を挽回するには遅すぎるのう。","ENG":"Yes, it is too late to make up for our lost opportunities.","TWN":"沒錯，想挽回我們錯失的機會已經來不及，"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 최악의 상황을 막을 방법은 아직 남아있다.","JPN":"しかし、最悪の状況を止められる方法はまだ残っておる。","ENG":"But there is still a way to stop the worst.","TWN":"但是還有辦法阻止最壞的情況發生。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 시도마저도 저들의 계획이라면…… 그땐 어쩌면 좋죠?","JPN":"その方法までも彼らの計画のうちだったら……その時はどうしたらよいのですか？","ENG":"And if that is also a part of their plan...? What do we do then?","TWN":"如果連這個辦法也在他們的計畫之內……到時候該怎麼辦呢？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};